function aStarGridShortestPath(grid: number[][], start: readonly [number, number], end: readonly [number, number]): number | null {
  const rows = grid.length;
  if (rows === 0) return null;
  const cols = grid[0].length;

  const [startR, startC] = start;
  const [endR, endC] = end;

  if (
    startR < 0 || startR >= rows || startC < 0 || startC >= cols ||
    endR < 0 || endR >= rows || endC < 0 || endC >= cols ||
    grid[startR][startC] === 1 || grid[endR][endC] === 1
  ) {
    return null;
  }

  const heuristic = (r: number, c: number) => Math.abs(r - endR) + Math.abs(c - endC);

  class MinHeap {
    nodes: { r: number; c: number; f: number }[] = [];
    push(node: { r: number; c: number; f: number }) {
      this.nodes.push(node);
      let index = this.nodes.length - 1;
      while (index > 0) {
        let parent = Math.floor((index - 1) / 2);
        if (this.nodes[parent].f <= this.nodes[index].f) break;
        [this.nodes[parent], this.nodes[index]] = [this.nodes[index], this.nodes[parent]];
        index = parent;
      }
    }
    pop() {
      if (this.nodes.length === 0) return null;
      const min = this.nodes[0];
      const last = this.nodes.pop()!;
      if (this.nodes.length > 0) {
        this.nodes[0] = last;
        let index = 0;
        while (true) {
          let left = 2 * index + 1;
          let right = 2 * index + 2;
          let smallest = index;
          if (left < this.nodes.length && this.nodes[left].f < this.nodes[smallest].f) smallest = left;
          if (right < this.nodes.length && this.nodes[right].f < this.nodes[smallest].f) smallest = right;
          if (smallest === index) break;
          [this.nodes[smallest], this.nodes[index]] = [this.nodes[index], this.nodes[smallest]];
          index = smallest;
        }
      }
      return min;
    }
    size() { return this.nodes.length; }
  }

  const openSet = new MinHeap();
  const gScore = new Map<string, number>();

  const startKey = `${startR},${startC}`;
  gScore.set(startKey, 0);
  openSet.push({ r: startR, c: startC, f: heuristic(startR, startC) });

  const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

  while (openSet.size() > 0) {
    const current = openSet.pop()!;
    const { r, c, f } = current;

    const currentG = gScore.get(`${r},${c}`)!;
    if (f > currentG + heuristic(r, c)) continue;

    if (r === endR && c === endC) return currentG;

    for (const [dr, dc] of directions) {
      const nr = r + dr;
      const nc = c + dc;

      if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc] === 0) {
        const tentativeG = currentG + 1;
        const neighborKey = `${nr},${nc}`;
        const neighborG = gScore.get(neighborKey);

        if (neighborG === undefined || tentativeG < neighborG) {
          gScore.set(neighborKey, tentativeG);
          openSet.push({ r: nr, c: nc, f: tentativeG + heuristic(nr, nc) });
        }
      }
    }
  }

  return null;
}

function binarySearchBoundary(values: number[], target: number): number {
  let low = 0;
  let high = values.length - 1;
  let result = -1;

  while (low <= high) {
    const mid = Math.floor(low + (high - low) / 2);

    if (values[mid] === target) {
      result = mid;
      high = mid - 1;
    } else if (values[mid] < target) {
      low = mid + 1;
    } else {
      high = mid - 1;
    }
  }

  return result;
}

function binarySearchFirstLastPosition(values: number[], target: number): [number, number] {
  let first = -1;
  let low = 0;
  let high = values.length - 1;

  while (low <= high) {
    const mid = Math.floor((low + high) / 2);
    if (values[mid] === target) {
      first = mid;
      high = mid - 1;
    } else if (values[mid] < target) {
      low = mid + 1;
    } else {
      high = mid - 1;
    }
  }

  if (first === -1) {
    return [-1, -1];
  }

  let last = -1;
  low = first;
  high = values.length - 1;

  while (low <= high) {
    const mid = Math.floor((low + high) / 2);
    if (values[mid] === target) {
      last = mid;
      low = mid + 1;
    } else if (values[mid] < target) {
      low = mid + 1;
    } else {
      high = mid - 1;
    }
  }

  return [first, last];
}
